const out = [];

function decodeHtml(str) {
  return String(str || "")
    .replace(/&nbsp;/gi, " ")
    .replace(/&#160;/g, " ")
    .replace(/&amp;/gi, "&")
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/g, "'")
    .replace(/&ndash;/gi, "–")
    .replace(/&mdash;/gi, "—")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">");
}

function stripTags(str) {
  return String(str || "")
    .replace(/<script[\s\S]*?<\/script>/gi, " ")
    .replace(/<style[\s\S]*?<\/style>/gi, " ")
    .replace(/<sup[\s\S]*?<\/sup>/gi, " ")
    .replace(/<[^>]+>/g, " ");
}

function cleanText(str) {
  return decodeHtml(stripTags(str)).replace(/\s+/g, " ").trim();
}

function normalizeRound(raw, stageType) {
  const txt = cleanText(raw || "").toLowerCase();

  if (stageType === "group_stage") {
    const g = txt.match(/group\s+([a-h])/i);
    if (g) return `group_${g[1].toUpperCase()}`;
    if (txt.includes("group stage")) return "group_stage";
    return null;
  }

  if (stageType === "knockout_phase") {
    if (txt.includes("round of 16")) return "round_of_16";
    if (txt.includes("quarter-final")) return "quarter_finals";
    if (txt.includes("semi-final")) return "semi_finals";
    if (txt === "final" || txt.includes(" final")) return "final";
    if (txt.includes("knockout phase")) return "knockout_phase";
    return null;
  }

  return null;
}

function getClosestFootballboxContext(html, start, end) {
  const lower = html.toLowerCase();

  const boxStart = lower.lastIndexOf('footballbox', start);
  const prevDivStart = boxStart !== -1
    ? lower.lastIndexOf('<div', boxStart)
    : -1;

  const nextBoxStart = lower.indexOf('footballbox', end + 1);

  if (prevDivStart !== -1) {
    const sliceEnd = nextBoxStart !== -1
      ? nextBoxStart
      : Math.min(html.length, end + 2500);

    return html.slice(prevDivStart, sliceEnd);
  }

  // fallback seguro si no encontramos footballbox claro
  return html.slice(
    Math.max(0, start - 1200),
    Math.min(html.length, end + 1200)
  );
}

for (const item of $input.all()) {
  const html = decodeHtml(item.json.parse?.text?.["*"] || "");

  const season_label = item.json.label || item.json.season_label || null;
  const season_slug = item.json.slug || item.json.season_slug || null;
  const stage_type = item.json.stage_type || null;
  const source = item.json.source || "wikipedia";

  const tokenRegex =
    /(<div class="mw-heading[\s\S]*?<\/div>)|(<h[2-4][^>]*>[\s\S]*?<\/h[2-4]>)|(<table[\s\S]*?<\/table>)/gi;

  let match;
  let currentRound = normalizeRound(stage_type, stage_type);
  let knockoutTables = [];

  while ((match = tokenRegex.exec(html)) !== null) {
    const token = match[0];
    const start = match.index;
    const end = start + token.length;

    const isTable = token.toLowerCase().startsWith("<table");
    const isHeading = !isTable;

    if (isHeading) {
      const headingText = cleanText(token);
      const detected = normalizeRound(headingText, stage_type);
      if (detected) currentRound = detected;
      continue;
    }

    // SOLO tablas de partido real
    const isFevent =
      token.includes('class="fevent"') ||
      token.includes("class='fevent'");

    if (!isFevent) {
      continue;
    }

    const context_html = getClosestFootballboxContext(html, start, end);

    const row = {
      json: {
        season_label,
        season_slug,
        stage_type,
        round_hint: currentRound || null,
        source,
        table_html: token,
        context_html
      }
    };

    out.push(row);

    if (stage_type === "knockout_phase") {
      knockoutTables.push(row);
    }
  }

  // parche inteligente:
  // si estamos en knockout y no se detectó ninguna tabla como final,
  // marcamos la última tabla útil como final
  if (stage_type === "knockout_phase" && knockoutTables.length > 0) {
    const hasFinal = knockoutTables.some(x => x.json.round_hint === "final");

    if (!hasFinal) {
      knockoutTables[knockoutTables.length - 1].json.round_hint = "final";
    }
  }
}

return out;

const out = [];

// ---------------- helpers ----------------
function decodeHtml(str) {
  return String(str || "")
    .replace(/&nbsp;/gi, " ")
    .replace(/&#160;/g, " ")
    .replace(/&amp;/gi, "&")
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/g, "'")
    .replace(/&ndash;/gi, "–")
    .replace(/&mdash;/gi, "—")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">");
}

function stripTags(str) {
  return String(str || "")
    .replace(/<script[\s\S]*?<\/script>/gi, " ")
    .replace(/<style[\s\S]*?<\/style>/gi, " ")
    .replace(/<sup[\s\S]*?<\/sup>/gi, " ")
    .replace(/<[^>]+>/g, " ");
}

function cleanText(str) {
  return decodeHtml(stripTags(str)).replace(/\s+/g, " ").trim();
}

function extractBlock(html, className) {
  const re = new RegExp(
    `<th[^>]*class="[^"]*${className}[^"]*"[^>]*>([\\s\\S]*?)<\\/th>`,
    "i"
  );
  const m = html.match(re);
  return m ? m[1] : "";
}

function extractDate(contextHtml) {
  const txt = cleanText(contextHtml || "");
  const m = txt.match(/\b(\d{1,2}\s+[A-Za-zÀ-ÿ]+\s+\d{4})\b/);
  return m ? m[1] : null;
}

function extractKickoffTime(contextHtml) {
  const txt = cleanText(contextHtml || "");
  const m = txt.match(/\b(\d{1,2}:\d{2})\b/);
  return m ? m[1] : null;
}

function extractAttendance(contextHtml) {
  const txt = cleanText(contextHtml || "");
  const m = txt.match(/Attendance:\s*([\d.,]+)/i);
  if (!m) return null;

  const n = Number(
    String(m[1])
      .replace(/[.,](?=\d{3}\b)/g, "")
      .replace(/[^\d]/g, "")
  );

  return Number.isFinite(n) ? n : null;
}

function extractVenue(contextHtml) {
  const html = String(contextHtml || "");

  const m = html.match(
    /itemprop="location"[\s\S]*?<span[^>]*itemprop="name address"[^>]*>([\s\S]*?)<\/span>/i
  );

  if (!m) {
    return { stadium_raw: null, city_raw: null };
  }

  const venueText = cleanText(m[1]);
  if (!venueText) {
    return { stadium_raw: null, city_raw: null };
  }

  const parts = venueText.split(",").map(x => x.trim()).filter(Boolean);

  if (parts.length >= 2) {
    return {
      stadium_raw: parts[0] || null,
      city_raw: parts.slice(1).join(", ") || null
    };
  }

  return {
    stadium_raw: venueText,
    city_raw: null
  };
}

function parseScoreMeta(scoreRaw) {
  const scoreText = cleanText(scoreRaw || "");

  const baseMatch = scoreText.match(/(\d{1,2})\s*[–-]\s*(\d{1,2})/);
  if (!baseMatch) return null;

  const home_score = Number(baseMatch[1]);
  const away_score = Number(baseMatch[2]);

  const lower = scoreText.toLowerCase();

  const went_extra_time =
    /\b(a\.?e\.?t\.?|after extra time|extra time|prórroga|prolongación)\b/i.test(lower);

  const went_penalties =
    /\b(pens?\.?|penalties|penalty shoot-?out|on penalties|after penalties)\b/i.test(lower);

  let home_penalty_score = null;
  let away_penalty_score = null;

  // Casos típicos:
  // 1–1 (4–3 pen.)
  // 1–1 (4-3 pens)
  // 1–1 (4–3 on penalties)
  const penMatch = scoreText.match(/\((\d{1,2})\s*[–-]\s*(\d{1,2})\s*(?:pen\.?|pens\.?|penalties|on penalties)?\)/i);
  if (penMatch) {
    home_penalty_score = Number(penMatch[1]);
    away_penalty_score = Number(penMatch[2]);
  }

  let win_method = "regular_time";
  if (went_penalties) {
    win_method = "penalties";
  } else if (went_extra_time) {
    win_method = "extra_time";
  }

  return {
    score_text: scoreText,
    home_score,
    away_score,
    went_extra_time,
    went_penalties,
    home_penalty_score,
    away_penalty_score,
    win_method
  };
}

// ---------------- team clean ----------------
function cleanTeam(str) {
  let s = cleanText(str);

  const aliases = {
    "Man. City": "Manchester City",
    "Man City": "Manchester City",
    "Man. United": "Manchester United",
    "Man United": "Manchester United",
    "PSG": "Paris Saint-Germain",
    "Inter": "Inter Milan",
    "Milan": "AC Milan",
    "Bayern": "Bayern Munich",
    "Brugge": "Club Brugge",
    "Copenhagen": "FC Copenhagen",
    "Dinamo": "Dinamo Zagreb",
    "Plzeň": "Viktoria Plzen",
    "Plzen": "Viktoria Plzen",
    "M. Haifa": "Maccabi Haifa",
    "R. Sociedad": "Real Sociedad",
    "Internazionale": "Inter Milan",
    "Red Bull Salzburg": "Red Bull Salzburg",
    "Tottenham Hotspur": "Tottenham Hotspur"
  };

  s = s.replace(/[,:;.\-–—]+$/g, "").trim();
  return aliases[s] || s;
}

function looksValidTeam(s) {
  if (!s) return false;
  if (s.length < 2 || s.length > 60) return false;
  if (/^\d+$/.test(s)) return false;

  const banned = [
    "Report",
    "Match report",
    "Goals",
    "Penalty",
    "Own goal",
    "Group stage",
    "Knockout phase",
    "Top goalscorers"
  ];

  return !banned.some(x => s.includes(x));
}

// ---------------- round helpers ----------------
function normalizeRound(round, stageType) {
  const txt = cleanText(round || "").toLowerCase();

  if (!txt) return null;

  if (stageType === "group_stage") {
    const g = txt.match(/group[_\s-]*([a-h])/i);
    if (g) return `group_${g[1].toUpperCase()}`;
    if (txt === "group_stage" || txt === "group stage") return "group_stage";
  }

  if (stageType === "knockout_phase") {
    if (txt.includes("round of 16") || txt.includes("round_of_16")) return "round_of_16";
    if (txt.includes("quarter-final") || txt.includes("quarter_finals")) return "quarter_finals";
    if (txt.includes("semi-final") || txt.includes("semi_finals")) return "semi_finals";
    if (txt === "final" || txt.endsWith(" final")) return "final";
    if (txt === "knockout_phase" || txt === "knockout phase") return "knockout_phase";
  }

  return round || null;
}

function detectRound(contextHtml, stageType) {
  const txt = cleanText(contextHtml || "").toLowerCase();

  if (stageType === "group_stage") {
    const groupMatch = txt.match(/group\s+([a-h])/i);
    if (groupMatch) return `group_${groupMatch[1].toUpperCase()}`;
    return "group_stage";
  }

  if (stageType === "knockout_phase") {
    if (txt.includes("round of 16")) return "round_of_16";
    if (txt.includes("quarter-final")) return "quarter_finals";
    if (txt.includes("semi-final")) return "semi_finals";
    if (txt.includes("final")) return "final";
    return "knockout_phase";
  }

  return null;
}

// ---------------- main ----------------
for (const item of $input.all()) {
  const tableHtml = item.json.table_html || "";
  const contextHtml = item.json.context_html || "";

  if (!tableHtml.includes('class="fevent"')) continue;

  const homeRaw = extractBlock(tableHtml, "fhome");
  const scoreRaw = extractBlock(tableHtml, "fscore");
  const awayRaw = extractBlock(tableHtml, "faway");

  if (!homeRaw || !scoreRaw || !awayRaw) continue;

  const scoreMeta = parseScoreMeta(scoreRaw);
  if (!scoreMeta) continue;

  const home_team = cleanTeam(homeRaw);
  const away_team = cleanTeam(awayRaw);

  if (!looksValidTeam(home_team) || !looksValidTeam(away_team)) continue;
  if (home_team === away_team) continue;

  const rawStageType = item.json.stage_type || null;
  const stage_type = rawStageType === "final_only" ? "knockout_phase" : rawStageType;

  let round;

  if (rawStageType === "final_only") {
    round = "final";
  } else {
    round =
      normalizeRound(item.json.round_hint || null, stage_type) ||
      normalizeRound(item.json.round || null, stage_type) ||
      detectRound(contextHtml, stage_type);
  }

  const match_date = extractDate(contextHtml);
  const kickoff_time = extractKickoffTime(contextHtml);
  const attendance = extractAttendance(contextHtml);
  const venue = extractVenue(contextHtml);

  out.push({
    json: {
      season_label: item.json.season_label || null,
      season_slug: item.json.season_slug || null,
      stage_type,
      round,
      home_team,
      home_score: scoreMeta.home_score,
      away_score: scoreMeta.away_score,
      away_team,
      match_date,
      kickoff_time,
      stadium_raw: venue.stadium_raw,
      city_raw: venue.city_raw,
      attendance,
      went_extra_time: scoreMeta.went_extra_time,
      went_penalties: scoreMeta.went_penalties,
      home_penalty_score: scoreMeta.home_penalty_score,
      away_penalty_score: scoreMeta.away_penalty_score,
      win_method: scoreMeta.win_method,
      score_text: scoreMeta.score_text,
      source: item.json.source || "wikipedia"
    }
  });
}

// ---------------- dedupe ----------------
const seen = new Set();
const deduped = [];

for (const item of out) {
  const x = item.json;
  const key = [
    x.season_slug || "",
    x.stage_type || "",
    x.round || "",
    x.match_date || "",
    x.kickoff_time || "",
    x.home_team,
    x.home_score,
    x.away_score,
    x.away_team,
    x.home_penalty_score ?? "",
    x.away_penalty_score ?? ""
  ].join("|");

  if (seen.has(key)) continue;
  seen.add(key);
  deduped.push(item);
}

return deduped;

const out = [];

for (const item of $input.all()) {
  const j = item.json;
  const slug = String(j.slug || "");
  const slugEnDash = slug.replace(/-/g, "–");

  const startYear = slug.split("-")[0];
  const endYearShort = slug.split("-")[1];
  const finalYear = startYear && endYearShort
    ? `20${endYearShort}`
    : null;

  out.push({
    json: {
      ...j,
      stage_type: "group_stage",
      wiki_page: `${slugEnDash}_UEFA_Champions_League_group_stage`
    }
  });

  out.push({
    json: {
      ...j,
      stage_type: "knockout_phase",
      wiki_page: `${slugEnDash}_UEFA_Champions_League_knockout_phase`
    }
  });

  if (finalYear) {
    out.push({
      json: {
        ...j,
        stage_type: "final_only",
        wiki_page: `${finalYear}_UEFA_Champions_League_final`
      }
    });
  }
}

return out;

const counts = {};

for (const item of $input.all()) {
  const r = item.json.round || "unknown";
  counts[r] = (counts[r] || 0) + 1;
}

return Object.entries(counts).map(([round, total]) => ({
  json: { round, total }
}));

function normalizeName(name) {
  return String(name || "")
    .trim()
    .replace(/\s+/g, " ")
    .replace(/[’']/g, "'")
    .replace(/[^\w\s.'-]/g, "")
    .trim();
}

function slugify(text) {
  return String(text || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

// 🔥 alias DEFINITIVO (puedes ampliarlo luego)
const TEAM_ALIASES = {
  "Inter": "Inter Milan",
  "Internazionale": "Inter Milan",
  "Milan": "AC Milan",
  "PSG": "Paris Saint-Germain",
  "Man City": "Manchester City",
  "Man. City": "Manchester City",
  "Man United": "Manchester United",
  "Man. United": "Manchester United",
  "Bayern": "Bayern Munich",
  "Napoli": "Napoli",
  "Real Madrid CF": "Real Madrid",
  "FC Barcelona": "Barcelona"
};

const out = [];

for (const item of $input.all()) {
  let home = normalizeName(item.json.home_team);
  let away = normalizeName(item.json.away_team);

  // aplicar alias
  home = TEAM_ALIASES[home] || home;
  away = TEAM_ALIASES[away] || away;

  out.push({
    json: {
      ...item.json,

      home_team: home,
      away_team: away,

      home_team_slug: slugify(home),
      away_team_slug: slugify(away)
    }
  });
}

return out;

const seen = new Set();
const out = [];

for (const item of $input.all()) {
  const j = item.json;

  const teams = [
    { name: j.home_team, slug: j.home_team_slug },
    { name: j.away_team, slug: j.away_team_slug }
  ];

  for (const t of teams) {
    const name = String(t.name || "").trim();
    const slug = String(t.slug || "").trim();

    if (!name || !slug) continue;
    if (seen.has(slug)) continue;

    seen.add(slug);

    out.push({
      json: {
        name,
        slug
      }
    });
  }
}

return out;

const items = $input.all();

const scrapedTeams = [];
const dbTeams = [];
const dbAliases = [];

for (const item of items) {
  const j = item.json;

  // aliases
  if (j.alias_slug) {
    dbAliases.push(j);
    continue;
  }

  // teams reales de BD
  if (j.id && j.slug) {
    dbTeams.push(j);
    continue;
  }

  // equipos scrapeados
  if (j.name && j.slug) {
    scrapedTeams.push(j);
    continue;
  }
}

const teamSlugs = new Set(
  dbTeams
    .map(t => String(t.slug || "").trim().toLowerCase())
    .filter(Boolean)
);

const aliasSlugs = new Set(
  dbAliases
    .map(a => String(a.alias_slug || "").trim().toLowerCase())
    .filter(Boolean)
);

const out = [];

for (const e of scrapedTeams) {
  const slug = String(e.slug || "").trim().toLowerCase();
  if (!slug) continue;

  const existsInTeams = teamSlugs.has(slug);
  const existsInAliases = aliasSlugs.has(slug);

  if (!existsInTeams && !existsInAliases) {
    out.push({ json: e });
  }
}

return out;

const items = $input.all();

const matches = [];
const dbTeams = [];
const dbAliases = [];

// Separar tipos de items
for (const item of items) {
  const j = item.json;

  // aliases
  if (j.alias_slug) {
    dbAliases.push(j);
    continue;
  }

  // teams reales
  if (j.id && j.slug && j.name) {
    dbTeams.push(j);
    continue;
  }

  // matches normalizados
  if (
    j.home_team &&
    j.away_team &&
    Object.prototype.hasOwnProperty.call(j, "home_score") &&
    Object.prototype.hasOwnProperty.call(j, "away_score")
  ) {
    matches.push(j);
    continue;
  }
}

// Mapas rápidos
const teamBySlug = new Map();
for (const t of dbTeams) {
  const slug = String(t.slug || "").trim().toLowerCase();
  if (!slug) continue;
  teamBySlug.set(slug, t);
}

const teamIdByAliasSlug = new Map();
for (const a of dbAliases) {
  const aliasSlug = String(a.alias_slug || "").trim().toLowerCase();
  if (!aliasSlug) continue;
  teamIdByAliasSlug.set(aliasSlug, a.team_id);
}

// Resolver equipo por slug
function resolveTeam(slug) {
  const s = String(slug || "").trim().toLowerCase();
  if (!s) {
    return {
      id: null,
      found: false,
      via: null,
    };
  }

  const directTeam = teamBySlug.get(s);
  if (directTeam) {
    return {
      id: directTeam.id,
      found: true,
      via: "teams",
    };
  }

  const aliasTeamId = teamIdByAliasSlug.get(s);
  if (aliasTeamId) {
    return {
      id: aliasTeamId,
      found: true,
      via: "aliases",
    };
  }

  return {
    id: null,
    found: false,
    via: null,
  };
}

const out = [];

for (const m of matches) {
  const home = resolveTeam(m.home_team_slug);
  const away = resolveTeam(m.away_team_slug);

  out.push({
    json: {
      ...m,
      home_team_id: home.id,
      away_team_id: away.id,
      home_team_found: home.found,
      away_team_found: away.found,
      home_team_resolved_via: home.via,
      away_team_resolved_via: away.via,
      teams_resolved_ok: home.found && away.found,
    }
  });
}

return out;

const items = $input.all();

const seasonMeta = items.find(item => item.json.kind === 'season_meta');
const matches = items.filter(item => item.json.kind !== 'season_meta');

if (!seasonMeta) {
  throw new Error('No llegó season_meta');
}

return matches.map(item => ({
  json: {
    ...item.json,
    competition_id: seasonMeta.json.competition_id,
    competition_season_id: seasonMeta.json.id,
    season: seasonMeta.json.season_label
  }
}));
